Input: {"user":"ahmad__mamoon","comment":"❤️","hasParent":false,"parent":null}
Output: {"reply": "❤️"}

Input: {"user":"ahmad__mamoon","comment":"Great post!","hasParent":false,"parent":null}
Output: {"reply": "Thanks so much! 😊"}

Input: {"user":"ahmad__mamoon","comment":"How did you do this?","hasParent":true,"parent":{"user":"test","text":"Amazing work"}}
Output: {"reply": "I used n8n automation! Would you like to know more?"}

