    const entry = body.entry[0];
    let shouldSkip = false;

    // Check comments
    if (entry.changes && entry.changes[0] && entry.changes[0].field === "feed") {
      const value = entry.changes[0].value;
      if (value.item === "comment" && value.from.id === myFacebookPageId) {
        shouldSkip = true; // Skip my page's comments
      }
    }

    // Check messages
    if (entry.messaging && entry.messaging[0] && 
        entry.messaging[0].sender.id === myFacebookPageId) {
      shouldSkip = true; // Skip my page's messages
    }

    if (!shouldSkip) {
      filteredItems.push(item);
    }
  } else {
    // Keep non-Facebook items
    filteredItems.push(item);
  }
}

